function mincostToHireWorkers(quality, wage, K) {
    const workers = Array.from({length: quality.length}, (_, i) => [
        wage[i] / quality[i], quality[i],
    ]).sort((a, b) => a[0] - b[0]);

    let sumQuality = 0;
    const maxHeap = new MaxHeap(comparator);

    let result = Infinity;
    for (const [ratio, q] of workers) {
        maxHeap.add(q);
        sumQuality += q;

        if (maxHeap.size() > K) {
            sumQuality -= maxHeap.pop();
        }

        if (maxHeap.size() === K) {
            result = Math.min(result, ratio * sumQuality);
        }
    }

    return result;
}

class MaxHeap {
    constructor(comparator) {
        this._heap = [];
        this._comparator = comparator;
    }

    add(value) {
        this._heap.push(value);
        this.bubbleUp(this.size() - 1);
    }

    pop() {
        if (this.isEmpty()) return undefined;

        this.swap(0, this.size() - 1);
        const result = this._heap.pop();
        this.bubbleDown(0);
        return result;
    }

    size() {
        return this._heap.length;
    }

    isEmpty() {
        return this._heap.length === 0;
    }

    bubbleUp(index) {
        const parent = this.parent(index);
        if (parent >= 0 && this._compare(parent, index)) {
            this.swap(parent, index);
            this.bubbleUp(parent);
        }
    }

    bubbleDown(index) {
        const largest = this.maxChildIndex(index);
        if (largest !== -1 && this._compare(index, largest)) {
            this.swap(index, largest);
            this.bubbleDown(largest);
        }
    }

    parent(index) {
        return index <= 0 ? -1 : Math.floor((index - 1) / 2);
    }

    maxChildIndex(index) {
        const left = index * 2 + 1;
        const right = index * 2 + 2;
        if (left >= this.size()) return -1;

        if (right >= this.size()) return left;

        return this._compare(left, right) ? right : left;
    }

    swap(i, j) {
        [this._heap[i], this._heap[j]] = [this._heap[j], this._heap[i]];
    }

    _compare(i, j) {
        return this._comparator(this._heap[i], this._heap[j]);
    }
}

function comparator(a, b) {
    return a < b;
}
```

    We represent each worker as a pair of `(wage / quality, quality)`. We sort these workers based on the wage-to-quality ratio, making it easier to track the cost of hiring each worker. The algorithm maintains a priority queue, which is initially empty. The total quality sum starts at 0. 

We iterate through the sorted workers, for each worker:
1. Add their quality value to the max heap and increment the total quality sum.
2. If max heap size is greater than `k`, we subtract the largest quality value from the sum and pop it from the max heap.
3. If max heap size equals `k`, we update the result with the minimum of the current result and the product of the total quality sum and the current worker's wage-to-quality ratio.

Finally, we return the lowest cost.

